using Microsoft.EntityFrameworkCore;
class MigrationRunner
{
    // EF Core 9 manages its own transactions during Migrate(); wrapping in
    // a user transaction now throws. Simply call Migrate() directly.
    void ApplyMigrations(AppDbContext db)
    {
        db.Database.Migrate();
    }
}

