using Microsoft.EntityFrameworkCore;

class CosmosDbContext : DbContext
{
    public DbSet<Session> Sessions => Set<Session>();
    public DbSet<Product> Products => Set<Product>();

    protected override void OnConfiguring(DbContextOptionsBuilder options)
    {
        options.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=placeholder",
            "MyDatabase");
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF Core 9 changed the default discriminator property from "Discriminator" to "$type".
        // Existing documents use "Discriminator", so explicitly configure the old name.
        modelBuilder.Entity<Session>().HasDiscriminator<string>("Discriminator");
        modelBuilder.Entity<Product>().HasDiscriminator<string>("Discriminator");

        // EF Core 9 changed the id format from "EntityType|KeyValue" to just "KeyValue".
        // Existing documents use the old compound format; preserve it for backward compat.
        modelBuilder.Entity<Session>().HasRootDiscriminatorInJsonId(true);
        modelBuilder.Entity<Product>().HasRootDiscriminatorInJsonId(true);
    }
}

class CosmosQueryService
{
    // EF Core 9 Cosmos provider no longer supports synchronous I/O.
    // All queries and SaveChanges must use async equivalents.
    async Task<List<Product>> GetProductsAsync(CosmosDbContext db)
    {
        // Before (throws in EF Core 9):
        //   var products = db.Products.Where(p => p.Price > 10).ToList();
        //   db.SaveChanges();

        // After: use async methods
        var products = await db.Products.Where(p => p.Price > 10).ToListAsync();
        await db.SaveChangesAsync();
        return products;
    }
}

class Session { public string Id { get; set; } = ""; public string User { get; set; } = ""; }
class Product { public string Id { get; set; } = ""; public decimal Price { get; set; } }

